                <TextInput
                  style={styles.formInput}
                  value={manualForm.fat}
                  onChangeText={(text) => setManualForm({ ...manualForm, fat: text })}
                  placeholder="0"
                  keyboardType="numeric"
                />
              </View>
            </View>

            <View style={styles.formRow}>
              <View style={[styles.formGroup, { flex: 1 }]}>
